// Normaliza para búsqueda: minúsculas, sin tildes ni signos.
function norm(s) {
  return String(s || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[̀-ͯ]/g, '')
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

// Busca ciudades por nombre (y opcionalmente departamento). Prioriza:
// 1) ciudad exacta, 2) una palabra de la ciudad es exacta (ej "cali" → "Santiago De Cali"),
// 3) empieza con, 4) una palabra empieza con, 5) contiene, 6) match incluyendo departamento.
export function searchCities(query, limit = 10) {
  const q = norm(query);
  if (!q) return [];
  const scored = [];
  for (const row of CITIES) {
    const city = norm(row.c);
    const depto = norm(row.p);
    const words = city.split(' ');
    let score = -1;
    if (city === q) score = 0;
    else if (words.includes(q)) score = 1;
    else if (city.startsWith(q)) score = 2;
    else if (words.some((w) => w.startsWith(q))) score = 3;
    else if (city.includes(q)) score = 4;
    else if (`${city} ${depto}`.includes(q)) score = 5;
    if (score >= 0) scored.push({ score, row });
  }
  scored.sort((a, b) => a.score - b.score || a.row.c.localeCompare(b.row.c));
  return scored.slice(0, limit).map((s) => ({
    dane: s.row.d,
    depto: s.row.p,
    city: s.row.c,
  }));
}

// Devuelve una ciudad por su código DANE exacto (o null).
export function cityByDane(dane) {
  const d = String(dane || '').trim();
  const row = CITIES.find((r) => r.d === d);
  return row ? { dane: row.d, depto: row.p, city: row.c } : null;
}